+func resolveSpawnAssignAgentType(agent string, ccOnly, codOnly, gmiOnly bool) string {
+	if strings.TrimSpace(agent) != "" {
+		return strings.ToLower(agent)
+	}
+	if ccOnly {
+		return "claude"
+	}
+	if codOnly {
+		return "codex"
+	}
+	if gmiOnly {
+		return "gemini"
+	}
+	return ""
+}
